import { useLocation } from "react-router-dom";
import data from "./CategoryBooksData";
import "./styles/Books.css";

function LibrarianBooks() {
  const location = useLocation();
  const genre = location.state?.genre || "Literature";

  const books = data[genre] || [];

  return (
    <div className="books-page">
      <h1 className="books-title">{genre} Books</h1>

      <div className="books-grid">
        {books.map((book, index) => (
          <div className="book-card" key={index}>
            <img src={book.cover} alt={book.title} />
            <h3>{book.title}</h3>
            <p>{book.author}</p>
            <span className="card-status avail">Available</span>
          </div>
        ))}
      </div>
    </div>
  );
}

export default LibrarianBooks;
